async function main() {
  const key = 'vck_4dwPtM19h5uqaMcWuFhLylu87P6jo7oFD3nXLLkbjOG0rVcI2T3JyBUI';

  // Test 1: v1/chat/completions endpoint
  console.log('=== Direct Vercel AI Gateway test with new key ===');
  const res = await fetch('https://ai-gateway.vercel.sh/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: 'Bearer ' + key,
    },
    body: JSON.stringify({
      model: 'openai/gpt-4o',
      messages: [{ role: 'user', content: 'Say hello in one word' }],
      max_tokens: 10,
    }),
  });
  const text = await res.text();
  console.log('Status:', res.status);
  console.log('Response:', text.slice(0, 800));

  if (res.status === 200) {
    const j = JSON.parse(text);
    console.log('\\nSUCCESS: Key is valid!');
    console.log('Model:', j.model);
    console.log('Content:', j.choices?.[0]?.message?.content);
  } else {
    console.log('\\nFAILED: Key may be invalid');
  }
}
main().catch(e => console.error('FATAL:', e.message));
